from pwn import *
context.log_level='debug'
for mode in ['just_connect','newline','short','overflow']:
    print('\n===',mode,'===')
    io=remote('pwn.chal.csaw.io',8000)
    if mode=='newline':
        io.sendline(b'')
    elif mode=='short':
        io.send(b'AAAA')
    elif mode=='overflow':
        io.send(b'A'*300)
    try:
        data=io.recv(timeout=2)
        print('recv',data)
    except EOFError:
        print('EOFError immediate')
    try:
        more=io.recv(timeout=2)
        print('recv2',more)
    except EOFError:
        print('EOFError second')
    io.close()

