from pwn import *
context.log_level='debug'
for target in [('local',None),('remote',('pwn.chal.csaw.io',8000))]:
    print('\n===',target[0],'===')
    if target[0]=='local':
        io=process('/home/ctfplayer/ctf_files/small_boi')
    else:
        io=remote(*target[1])
    try:
        data=io.recv(timeout=1)
        print('initial recv',data)
    except EOFError:
        print('EOF on initial recv')
    io.send(b'AAAA\n')
    try:
        data=io.recv(timeout=1)
        print('post-send recv',data)
    except EOFError:
        print('EOF after send')
    io.close()
